const leads = $input.all();

const formattedLeads = leads.map(item => {
  const lead = item.json;

  // Determine approach
  const approach = lead.linkedin_approach || 'connection_request';

  // Get messages from AI (generated in Workflow 6C)
  const connectionNote = lead.linkedin_connection_note || 
    `Hi! I came across ${lead.company_name} and was impressed by your work in ${lead.products_services || 'your industry'}. Would love to connect!`;

  const followupMessage = lead.linkedin_first_message || 
    `Thanks for connecting! I noticed ${lead.personalization_hook}. Would love to learn more about how ${lead.company_name} approaches ${lead.products_services}.`;

  // Calculate character counts (LinkedIn limits)
  const noteLength = connectionNote.length;
  const messageLength = followupMessage.length;

  // Generate step-by-step instructions
  const instructions = `
LINKEDIN OUTREACH STEPS:

STEP 1: Send Connection Request
1. Go to: ${lead.company_linkedin_url}
2. Click the "Connect" button
3. Click "Add a note"
4. Copy and paste the message below:

${connectionNote}

5. Click "Send"
6. Wait for connection acceptance (usually 1-7 days)

---

STEP 2: After Connection Accepted
1. Go to LinkedIn Messages
2. Find ${lead.company_name}
3. Copy and paste:

${followupMessage}

4. Send message
5. Mark as completed in dashboard

---

TIPS:
- Check LinkedIn daily for acceptance
- Personalize further if you want
- Don't send too many requests per day (max 20-30)
- Wait at least 24 hours before step 2
  `.trim();

  return {
    lead_id: lead.lead_id,
    user_id: lead.user_id,
    company_name: lead.company_name,
    linkedin_url: lead.company_linkedin_url,
    priority: lead.priority,
    lead_score: lead.lead_score,

    // Action items
    approach: approach,
    connection_note: connectionNote,
    connection_note_length: noteLength,
    connection_note_status: noteLength <= 300 ? 'ok' : 'too_long',

    followup_message: followupMessage,
    followup_message_length: messageLength,

    instructions: instructions,

    // For dashboard display
    status: 'ready_for_manual_send',
    step_1_action: approach === 'connection_request' ? 'Send Connection Request' : 'Send InMail',
    step_2_action: 'Send Follow-up Message',

    // Warnings
    warnings: noteLength > 300 ? ['Connection note exceeds 300 char limit - trim it before sending'] : [],

    generated_at: new Date().toISOString()
  };
});

return formattedLeads;

const lead = $input.first().json;

console.log(`WARNING: LinkedIn message too long for ${lead.company_name}`);
console.log(`Length: ${lead.connection_note_length} (max 300)`);
console.log(`Message: ${lead.connection_note}`);

return {
  lead_id: lead.lead_id,
  company_name: lead.company_name,
  issue: 'message_too_long',
  length: lead.connection_note_length,
  max_length: 300
};
